var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"흠~ 흠흠~ 이제 슬슬 제 차례인가요?","JPN":"ふん～ふふん～そろそろ私の番でしょうか。","ENG":"*Humming* Is it almost my turn?","TWN":"哼哼♬～現在該輪到我了嗎？"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"무책임한 어머님과 비교하면 아직 부족하지만…….","JPN":"無責任なお母さんに比べるとまだまだ未熟ですけど……","ENG":"It isn't enough compared to my irresponsible Mother, but...","TWN":"雖然跟不負責任的母親相比，還有些不足……"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"제가 깊은 잠에 빠져 있던 동안, 기사님께서 충실하게 파편을 모아주셨거든요.","JPN":"私が深い眠りについている間、騎士様が真面目に破片を集めてくださったんです。","ENG":"While I was in deep slumber, my knight worked hard to gather Fragments.","TWN":"但在我熟睡的時候，騎士忠實地替我收集了碎片。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"덕분에 수많은 우리들이 다시 하나가 될 수 있었답니다.","JPN":"おかげで大勢の我々は再び一つになることができました。","ENG":"And so our countless selves were able to become one again.","TWN":"托你的福，無數的我們才能重新合而為一。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그러니까 이제 당신도 파편을 전부 제게 넘기고 하나가 되는 거예요.","JPN":"ですからあなたも破片をすべて私に渡して、一つになるのです。","ENG":"So you should hand over all your Fragments to me and become one with us.","TWN":"所以，把你的碎片也交給我，然後合而為一吧。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"……이브.","JPN":"……イヴ。","ENG":"...Eve.","TWN":"……伊芙。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"네가 누군지는 모르겠지만, 내 안의 파편은 아무한테도 안 넘길 거야.","JPN":"あなたが誰だかは知らないけど、私の中の破片は誰にも渡さない。","ENG":"I don't know who you are, but I'm not giving away the Fragment inside of me to anyone.","TWN":"雖然不知道你是誰，但是我不會把我的碎片交給任何人。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아무리 힘들고, 고통스러워도…… 언제까지나 꼭 참아내기로.","JPN":"どんなに辛くても苦しくても……いつまでも我慢するわ。","ENG":"I will endure... no matter how tiring or painful it is.","TWN":"無論多累多痛苦……我都會忍住。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 요원님과 약속했으니까.","JPN":"バーネット様と約束したから。","ENG":"That's what I promised Agent Burnett.","TWN":"因為我跟伯內特先生約好了。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그게 언제까지인데요?","JPN":"それはいつまでですか？","ENG":"And how long does that last?","TWN":"那麼，是到什麼時候？"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"응……?","JPN":"え……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"알고 계셨겠지만, 이곳에서의 시간은 아주 천천히 흐른답니다?","JPN":"わかっていると思いますが、ここでの時間はとてもゆっくり流れますよ。","ENG":"As you are probably aware, time flows extremely slowly here.","TWN":"你應該知道，這裡的時間流逝得很慢吧？"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"당신이 있던 현실에서는 이미 17년이라는 시간이 흘렀죠.","JPN":"あなたが生きていた現実では、すでに17年という歳月が経っています。","ENG":"It has already been 17 years in your original world.","TWN":"在你所在的現實中，已經過去了17年的時間。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그 현실에서의 <color=#ffd34c>1분</color>이 이곳에서는 대략 <color=#ffd34c>1시간</color>정도예요.","JPN":"その現実での<color=#ffd34c>1分</color>がここでは約<color=#ffd34c>1時間</color>にあたります。","ENG":"<color=#ffd34c>1 minute</color> in that world is around <color=#ffd34c>1 hour</color> in this world.","TWN":"現實中的<color=#ffd34c>1分鐘</color>在這裡大概是<color=#ffd34c>1小時</color>左右。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그렇다면, 17년이라는 시간은 이 세계 기준으로 따지면 어느 정도일지…….","JPN":"つまり、17年という期間はこの世界ではどれぐらいの時間になるか……","ENG":"Then, do you realize...","TWN":"那麼，以這個世界為准，17年的時間又是多長呢……"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"가늠이 되시나요?","JPN":"計算できますか？","ENG":"how long 17 years would be in this world?","TWN":"你能猜到嗎？"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"我，我……"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"당신의 파수꾼 노릇을 하던 안나 맥크레디는 영생을 추구하던 자였어요.","JPN":"あなたの番人をやっていたアンナ・マクレディーは、不老不死を求めていた者です。","ENG":"Your guard, Anna MacCready, was someone who pursued eternal life.","TWN":"你的守護者安娜·麥克蕾蒂，是一個追求永生的人。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그런, 그녀조차 시간의 무료함을 버티지 못하고 스스로를 동결시켰다가 필요할 때만 움직였죠.","JPN":"そんな彼女さえ、暇を持て余して自分自身を凍結させては必要な時にだけ動いていました。","ENG":"Even she could not withstand the monotony of time and froze herself, only moving when necessary.","TWN":"連她都沒能撐住時間的無聊，把自己凍結起來，只在需要的時候行動。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"당신도 비슷하죠?","JPN":"あなたも同じですよね？","ENG":"Aren't you doing something similar?","TWN":"你也一樣吧？"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"능력을 이용하여 과거로, 과거로…….","JPN":"能力を使って、過去へ、過去へ……","ENG":"You're using your abilities to go back, again and again...","TWN":"利用能力回到過去，再回到過去……"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"반복하고 있다는 사실조차 망각한 채, 그날의 꿈에 매달렸잖아요.","JPN":"繰り返しているということすら忘れ、あの日の夢に縋っていたじゃないですか。","ENG":"Clinging on to that dream, forgetting the fact that it was repeating.","TWN":"甚至忘記了不斷的重複，一直沉醉在那天的夢裡。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"시, 싫어……!","JPN":"い、嫌よ……！","ENG":"N-no...!","TWN":"不，不要……！"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"좋지도 않은 기억이었을 텐데, 꿈의 반복을 멈출 수 없었던 것은.","JPN":"あまりいい思い出でもなかったでしょうに、それでも夢を繰り返すことを止められなかったのは……","ENG":"It wasn't even a good memory. Yet, you could not stop repeating that dream.","TWN":"明明是不好的記憶，但卻無法停止夢的反復。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그렇게라도 하지 않으면…… 무척 외로웠을 테니까.","JPN":"そうでもしないと……寂しかったから。","ENG":"Because, if not for that... you would've felt very lonely.","TWN":"因為如果不那麼做……就會很孤獨。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"다시금 눈을 뜨면 혼자라는 사실을…… 버틸 수 없었을 테니까.","JPN":"目を開けると一人だという事実に……耐えきれなかったから。","ENG":"Because you would not have been able to handle the fact that... you are all alone when you open your eyes.","TWN":"因為再次睜開眼睛時，當發現自己是一個人後……會撐不下去。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"싫다고……!!","JPN":"いや……！！","ENG":"No...!!","TWN":"不要啊……！！"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"이제 그만, 그만해……!!","JPN":"もういや、やめて……！！","ENG":"Please, stop, just stop it...!!","TWN":"夠了，夠了……！！"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"흐윽, 나한테 그걸 알려주지 마! 내가 혼자라는 걸 알려주지 마!","JPN":"うぐっ……それを私に言わないで！　私が一人だということを言わないで！","ENG":"*Sob* Don't tell me that! Don't tell me that I'm alone!","TWN":"嗚嗚，不要跟我說那些！不要告訴我，我是獨自一人！"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"하지만 걱정하지 마세요, 이브.","JPN":"でも心配しないでください、イヴ。","ENG":"But don't worry, Eve.","TWN":"不過別擔心，伊芙。"},"stage":{"bg":"MIND","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_NULL","text":{"KOREA":"저희 가아그셰블라는 하나이자 전체, 전체이자 하나.","JPN":"我々ガアグシェブラは一つであり全て。全てであり一つ。","ENG":"We Gha'agsheblah are one and all. All and one.","TWN":"我們加格舍夫拉，既是一體也是全部，既是全部也是一體。"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_NULL","text":{"KOREA":"저희도 한때는 전부 이름과 형태를 가진 필멸자들이었답니다.","JPN":"我々もかつてはそれぞれ名前と形を持つ必滅者でした。","ENG":"We were also all mortals with names and forms.","TWN":"我們曾經也是有名字和形體的必滅者。"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_NULL","text":{"KOREA":"육체를 허물고, 마음을 섞어서, 그렇게 인간의 굴레를 벗어나 하나가 된다면.","JPN":"肉体が崩れ、心が交ざり、人間の形から抜け出して一つになれば。","ENG":"If we shed our skins, mix our minds, break free from the bounds of humanity, and become one.","TWN":"打破肉體，交融心靈，擺脫人類的束縛，合而為一。"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_NULL","text":{"KOREA":"시간과 공간 그리고 선과 악을 초월하여…… 결국은 서로를 이해할 수 있을 거예요.","JPN":"時間と空間、そして善と悪を超越し……やがては互いをわかり合えるはずです。","ENG":"We will transcend time and space, good and evil... and ultimately understand each other.","TWN":"超越時間和空間，超越善與惡……最終就可以相互理解了。"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 저에게…… 당신의 외로움을 주세요.","JPN":"ですから私に……あなたの寂しさをください。","ENG":"So... give me your loneliness.","TWN":"所以把你的孤獨……給我吧。"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_NULL","text":{"KOREA":"기쁨을 주세요, 분노를 주세요, 즐거움을 주세요, 고통을 주세요, 쾌락을 주세요.","JPN":"喜びをください。怒りをください。楽しさをください。苦痛をください。快楽をください。","ENG":"Give me your happiness, your anger, your joy, your pain, your pleasure.","TWN":"把你的開心、憤怒、愉悅、痛苦、快樂，都給我吧。"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_NULL","text":{"KOREA":"당신의 <color=#ffd34c>모든 걸</color> 탐식하게 해주세요.","JPN":"あなたの<color=#ffd34c>すべて</color>を貪食させてください。","ENG":"Let me devour <color=#ffd34c>everything</color> about you.","TWN":"讓我愉悅地享受你的<color=#ffd34c>一切</color>吧。"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_NULL","text":{"KOREA":"그리하면…… 비로소 우리는 <color=#ff3636>하나</color>가 될 수 있을 거예요.","JPN":"そうすれば……私たちは<color=#ff3636>一つ</color>になれるはずです。","ENG":"And then... we will be able to become <color=#ff3636>one</color>.","TWN":"那麼……我們終將能成為<color=#ff3636>一體</color>。"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"앗……?","JPN":"あっ…？","ENG":"Huh...?","TWN":"啊……？"},"stage":{"bg":"PRYDWEN_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"이브, 왜 이렇게 늦었니? 밥 다 식었잖아?","JPN":"イヴ、遅かったじゃない。食事が冷めちまったよ。","ENG":"Eve, what took you so long? The food is cold.","TWN":"伊芙，你怎麼來得這麼晚？飯都涼了。"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"벤자민 언니?","JPN":"ベンジャミンお姉さん？","ENG":"Benjamin?","TWN":"班潔明姊姊？"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"후후, 늦으셨군요. 이브. 한 달간 화장실 청소 당번이랍니다.","JPN":"ふふ、遅かったですね。イヴ、一か月間トイレ掃除当番です。","ENG":"Haha, you're late, Eve. You'll be cleaning the bathroom for a month.","TWN":"呵呵，你來晚了，伊芙。所以要打掃一個月廁所喔。"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"테오도라 수녀님?","JPN":"テオドラさん？","ENG":"Sister Theodora?","TWN":"狄奧朵拉修女？"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"얌마, 이브! 어떻게 책임질 거야?","JPN":"こら、イヴ！　どうしてくれるの！？","ENG":"Hey, Eve! Look what you've done!","TWN":"喂，伊芙！你要怎麼負責？"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"너 때문에 또 화장실 청소하게 생겼잖아!","JPN":"あなたのせいでまたトイレの当番になったじゃない！","ENG":"We're stuck cleaning the bathroom again because of you!","TWN":"因為你又要打掃廁所了！"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"앤……?","JPN":"アン……？","ENG":"Ann...?","TWN":"安妮……？"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"끄윽, 정말로……!","JPN":"ううっ、本当に……！","ENG":"*Sniffle.* Is it really...","TWN":"呃啊，真的……！"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"정말로…… 앤이야……?","JPN":"本当に……アンなの……？","ENG":"Is it really... you, Ann...?","TWN":"真的是……安妮嗎……？"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"기다리고 있었다. 이브.","JPN":"待っていた、イヴ。","ENG":"I've been waiting for you, Eve.","TWN":"我一直在等你，伊芙。"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"오랜 시간 동안 잘 버텨 주었어. 이제 참지 않아도 돼. ","JPN":"長い間、よく耐えてくれた。もう我慢しなくていい。 ","ENG":"You've done a good job, for a long time. You don't need to endure it anymore.","TWN":"這麼多年你都挺過來了，現在不用再忍了。"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"아아, 아아아아……!","JPN":"ああ、ああああ……！","ENG":"Aah, aaaaah...!","TWN":"啊啊，啊啊啊啊……！"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"다들! 다들, 여기 있었군요.","JPN":"みんな……！　みんな、ここにいたんですね。","ENG":"Everyone! Everyone, you were all here.","TWN":"大家！大家，原來都在這裡啊。"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"너무해요. 제가 그동안 얼마나 외로웠는데……!","JPN":"ひどい……私今まですごく寂しかったんですよ……！","ENG":"That's unfair. I was so lonely, all this time...!","TWN":"太過分了，你們知道這段時間我有多孤單嗎……！"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"혼자서…… 얼마나 힘들었는데……!","JPN":"一人で……辛かったんですよ……！","ENG":"It was so... tiring, all alone...!","TWN":"一個人……多累嗎……！"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_SHADOW","text":{"KOREA":"모두들……! 저, 다녀왔어요!","JPN":"みんな……！　ただいま！","ENG":"Everyone...! I'm back...!","TWN":"大家……！我，回來了！"},"stage":{"bg":"CHURCH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"으, 으아아아아악!!","JPN":"う、うわあああああ！！","ENG":"A-AHHHHHH!!","TWN":"咳，咳啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"대체 뭐가, 뭐가 태어나려 하는 거야……!!","JPN":"いったい何が、何が生まれるんだ……！！","ENG":"What in the hell is about to be born–","TWN":"到底是什麼，什麼東西要誕生了啊……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"어, 어머니의 보살핌 아래…… 우리는 곧……!","JPN":"は、母の腕の中で……我々はもうじき……！","ENG":"U-under Mother's care... we will soon...!","TWN":"在，在母親的關懷下……我們即將……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"으, 으아아악!! 사, 사, 사, 살려줘!!","JPN":"う、うわあああ！！　た、た、助けてくれ！！","ENG":"A-AHHH!! H-h-help!!","TWN":"呃，哢呃！！救，救，救，救命啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L1_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":" <color=#ff3636>버</color>…… <b>넷</b>.","JPN":" <color=#ff3636>バー</color>……<b>ネット</b>。","ENG":"<color=#ff3636>Bur</color>... <b>nett</b>.","TWN":"<color=#ff3636>伯</color>……<b>內特</b>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오오, 마침내! 마침내……!","JPN":"おお、ついに！　ついに……！","ENG":"Ohh, finally! Finally...!","TWN":"喔，終於！終於……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"클리파의 힘을 지닌 존재의 탄생을 직접 목도하는가……!","JPN":"クリファの力を持つ存在の誕生をこの目で見る時が来た……！","ENG":"I am able to witness the birth of a being that possesses the power of Qlipha...!","TWN":"終於可以親眼見證擁有逆卡巴拉力量的存在誕生……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"이 보잘 것 없고, 늙은 육체에서 벗어나! 신적 존재와 하나가……!","JPN":"このみすぼらしく老いぼれた肉体から離れ、神なる存在と一つ……！","ENG":"I can break free from this old, pathetic body! And become one with–","TWN":"擺脫這個渺小又年老的肉體！與神的存在合而為一……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"하, 하하! 하하하하하하하하!","JPN":"は、はは！　ははははははは！","ENG":"Ha, haha! Hahahahahaha!","TWN":"哈哈哈！哈哈哈哈哈！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"어처구니가 없네! 내가 저걸 얼마나 오랫동안 지켜왔는데!","JPN":"呆れちゃうわ！　私があれをどれほど長い間守って来たと思うの！","ENG":"Ridiculous! Do you know how long I've been guarding that?!","TWN":"真是不可理喻，我一直以來都在守護它！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"제기랄……! 그 역겨운 버넷의 손자만 아니었다면……!","JPN":"くそ……！　あのバーネットの孫じゃなければ……！","ENG":"Damn it...! If it weren't for that disgusting grandson of Burnett–!","TWN":"可惡……！要不是那個礙事的伯內特的孫子……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"흠~ 흠흠. 하나에서 여럿으로. 여럿에서 하나로.","JPN":"ふん〜ふんふん。一つから多数に。多数から一つに。","ENG":"*Humming* From one to all. From all to one.","TWN":"哼～哼哼♬。從一到多，從多到一。"},"stage":{"bg":"PRYDWEN_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_SHADOW_IN_TRAILER_1"},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"우리 모두 즐거운 성찬을 열도록 해요. 진리에 도달하기 위한 멋진 성찬을!","JPN":"みんな一緒に楽しい聖餐を開くことにしましょう。真理に到達するための素晴らしい聖餐を！","ENG":"Let us have a wonderful feast. A fantastic feast to reach the truth!","TWN":"大家一起舉辦一場開心的盛宴吧，能夠到達真理的美味盛宴！"},"stage":{"bg":"PRYDWEN_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_SHADOW_IN_TRAILER_2"},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"학회장도 기관장도…… 그리고 어머니도.","JPN":"学会長も機関長も……そしてお母さんも。","ENG":"The President, the Chief... and Mother.","TWN":"學會長、機關長……還有母親。"},"stage":{"bg":"PRYDWEN_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_SHADOW_IN_TRAILER_3"},{"id":"L21_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"모두 제 안에서 하나가 되어버린다면 더는 싸울 필요 없을 테니까요.","JPN":"皆私の中で一つになってしまえば、もう争う必要はありません。","ENG":"You won't need to fight if you become one within me.","TWN":"只要大家都在我裡面合而為一，哪還有必要再打下去呢。"},"stage":{"bg":"PRYDWEN_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_SHADOW_IN_TRAILER_4"},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"자, 그러니 제 품에 안겨 인간의 굴레 따윈 벗어버리도록 하세요.","JPN":"さあ、ですから私の腕の中で人間の形を脱ぎ捨てるのです。","ENG":"So, surrender yourselves to my embrace and break free from your human bounds.","TWN":"來吧，投入我的懷抱，脫離人類的束縛吧。"},"stage":{"bg":"PRYDWEN_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_SHADOW_IN_TRAILER_5"},{"id":"L23_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"……버넷.","JPN":"……バーネット。","ENG":"...Burnett.","TWN":"伯內特…"},"stage":{"bg":"PRYDWEN_01","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_SHADOW_IN_TRAILER_6"}]`);export{e as default};